nta.declaration:
/* AHB 20.11.23 This example feels very relevant since it is November and I'm working from home, seemingly unable to raise the temperature in my apartment above 20°C. This model was brought to you by Coop365™ Earl Gray. */

// Transmission coefficient
// https://fysikc.praxis.dk/2906
// https://bygningsreglementet.dk/Tekniske-bestemmelser/11/Krav/257#3e7c9938-9116-46a9-b468-2a571006ca9b
const double U_partition = 0.50;    // Transmission coefficient of inner walls. Unit: W/(m²·°C). Recall 1W=1J/s. 
const double U_exterior = 0.30;     // Ditto of exterior-facing walls. Unit: W/(m²·°C).
/* Example: 4m²·21°C·U_partition = 21°C·2W/°C = 43W */

// https://www.calculator.land/da/lommeregnere/termodynamiske-lommeregnere/varmekapacitet-lommeregner/
const double c_room = 1005.0;         // Specific heat capacity of the rooms. I assume the rooms are pure air. Unit: J/(kg·°C).
const double m_room = 100.41;          // Mass of a room interior. Wild guess since assuming pure air seems to create an oven. Unit: kg. 
const double mc_room = m_room*c_room; // Energy required to heat room 1 degree celcius. Unit: J/°C. 

const int hour = 60*60; // One Hour. Unit: s.
const int minute = 60;  // s.

const double T_ambient = 15;          // Ambient temperature. Unit: °C. 
hybrid clock T[4] = {23, 20, 21, 19}; // Temperature of room i. Unit: °C.
const int P_on = 150;       // Output of a heater turned on. By rights it should be 2000W, but that seems to turn the rooms into an oven. Unit: W.
int P[4];     // Power of the heaters. Unit: W.

const double A = 4.0;     // Area of a wall. All walls have the same area. Unit: m².

/** Going purely from these units I've look up, the temperature contribution from a single exterior wall would be:

    T[i]' == (T[i] - T_ambient)·A·U_exterior/mc_room

or the temperature contribution for a heater:

    T[i]' == P[i]/mc_room

Where the variables are as defined above.
*/ 

double debug1 = mc_room;
double debug2 = P_on/mc_room;
double debug3 = (21 - T_ambient)*A*U_exterior/mc_room;

clock time;

nta.system:
// Place template instantiations here.
// North-east, North-west, ...
Room0 = EndRoom(0, 1);
Room1 = Room(1);
Room2 = Room(2);
Room3 = EndRoom(3, 2);
Heater1 = Heater(0);
Heater2 = Heater(1);
Heater3 = Heater(2);
Heater4 = Heater(3);

system Room0, Room1, Room2, Room3, Heater1, Heater2, Heater3, Heater4;
